import{_ as t,c as o,o as r,ak as l}from"./chunks/framework.CYxz2ou1.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoMind/C-工作/3-2025面试/2.个人简历.md","filePath":"NanoMind/C-工作/3-2025面试/2.个人简历.md","lastUpdated":1775467143000}'),i={name:"NanoMind/C-工作/3-2025面试/2.个人简历.md"};function e(n,a,s,g,d,h){return r(),o("div",null,[...a[0]||(a[0]=[l('<h3 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h3><ul><li><strong>陈增</strong> 男 1996 年</li><li>电话/微信：<strong>15923021755</strong> 邮箱：1174520425@qq.com</li><li>求职意向：服务端开发工程师(<strong>4 年工作经验</strong> 在职)</li><li><strong>重庆大学</strong>：本科 机械工程学院 排名前 5% <strong>重庆大学</strong>：硕士 光电工程学院 排名前 5%</li></ul><h3 id="专业技能" tabindex="-1">专业技能 <a class="header-anchor" href="#专业技能" aria-label="Permalink to &quot;专业技能&quot;">​</a></h3><ul><li>熟悉 Java 核心知识（基础、并发、JVM 等），熟悉 Java 语言特性、JVM 原理等，有 OOM 问题排查与 GC 优化经验。</li><li>熟悉 Spring、Spring Boot、MyBatis 等主流开发框架及其架构设计原理。</li><li>熟悉 MySQL 基本原理(基础架构，事务，日志，索引，锁机制等)，有一定 SQL 优化，分库分表，数据迁移的项目经验。</li><li>熟悉 Redis 缓存、分布式锁等使用场景及 Redis 系统架构(主从，哨兵，集群)等，了解持久化机制及常见内存优化方案。</li><li>熟悉 RocketMQ、Kafka 等常见消息中间件的使用及原理。了解 Netty，ZooKeeper 等框架与中间件的基本架构与原理。</li><li>了解分布式系统的基本原理与常见问题的解决方案。有分布式锁，分布式数据一致性的落地经验。</li><li>有服务治理，流量控制，服务容错相关的经验。有系统架构设计，与系统重构相关经验。</li><li>了解大模型相关应用。</li><li>熟悉常用设计模式、设计原则等；了解 DDD 思想；遵循团队代码规范并有良好的代码；善长编写与管理技术文档。</li></ul><h3 id="工作经历" tabindex="-1">工作经历 <a class="header-anchor" href="#工作经历" aria-label="Permalink to &quot;工作经历&quot;">​</a></h3><h6 id="_2021-07-至今-猿辅导-工具应用部" tabindex="-1">2021.07-至今 猿辅导 工具应用部 <a class="header-anchor" href="#_2021-07-至今-猿辅导-工具应用部" aria-label="Permalink to &quot;2021.07-至今 猿辅导 工具应用部&quot;">​</a></h6><ul><li><strong>主 R 过 10+ 涉及多业务线、多人参与的项目</strong>。负责项目方案设计，梳理前置依赖与组织各端沟通对齐，把控项目进度与风险。负责项目均按时保质交付。</li><li><strong>服务治理与系统稳定性提升</strong>。参与多个核心业务的优化工作与日常稳定性治理工作，主要工作有：核心接口限流降级、服务与资源隔离拆分、大表优化（分库分表与数据迁移）、慢查治理、长尾请求优化、上游依赖资源合法性巡检、核心接口全链路压测与常态化压测、故障演练、故障应急预案、开学季预案、线上故障跟进与处理、流程规范制定等。核心业务<strong>可用性从 2 个 9 提升到 3 个 9</strong>。</li></ul><h3 id="项目经历" tabindex="-1">项目经历 <a class="header-anchor" href="#项目经历" aria-label="Permalink to &quot;项目经历&quot;">​</a></h3><h4 id="小猿学练机项目-核心领域负责人-多项目主-r-获得年度-a-绩效-2023-05-至今" tabindex="-1">小猿学练机项目(核心领域负责人/多项目主 R/获得年度 A 绩效) 2023.05-至今 <a class="header-anchor" href="#小猿学练机项目-核心领域负责人-多项目主-r-获得年度-a-绩效-2023-05-至今" aria-label="Permalink to &quot;小猿学练机项目(核心领域负责人/多项目主 R/获得年度 A 绩效) 2023.05-至今&quot;">​</a></h4><p><strong>项目描述</strong>：小猿学练机项目的核心产品是自研的<strong>智能设备</strong>，如墨水屏、安卓平板等。设备搭载了众多学习与练习相关的 APP，给用户提供诸多学习功能场景，如同步练习、AI 精准学、学情诊断等。</p><p><strong>工作内容</strong>：</p><ul><li><strong>全流程参与系统业务架构调整与重构落地</strong>。参与了基于 DDD 思想的领域建模与业务架构调整工作，将复杂业务拆分为 &quot;练习&quot;、&quot;学习&quot;、“基建” 等核心领域，解决原有架构因 4 年迭代导致的业务逻辑混乱、系统耦合严重、开发效率与质量低下的问题。主要负责了 “练习” 域的系统设计与重构。采用 DDD 思想解决练习场景下业务架构的梳理与建模，将练习域分为 “练习记录”、“批改”、“渲染” 等子领域，采用领域事件（如练习行为事件）的方式实现复杂业务系统之间的解耦，并对服务进行了职责边界划分。同时负责新系统架构开发落地、老系统数据与逻辑迁移、服务治理、新系统压测与性能优化、稳定性保障等工作。重构后开发效率显著提升，子领域内中规模需求平均开发交付周期从 2 周缩短至 1 周，练习流程服务可用性从 2 个 9 提升到 3 个 9 以上。</li><li><strong>基于服务端进行结构化题目图片渲染优化</strong>。针对墨水屏设备性能较低，存在题目本地渲染（将题目富文本信息渲染为图片）速度较慢的问题，采用基于 Node 进行渲染的服务端渲染优化方案。为保护 Node 渲染服务，使用 MySQL 持久化渲染结果，并使用本地缓存 Caffeine + 分布式 Redis 集群的二级缓存方式实现结果缓存。整体实现 95% 的缓存命中率，从出题到客户端渲染完成的平均耗时由 460ms 降低至 220ms。采用分库分表实现 10 亿级题目渲染图片的存储，并通过 Canal 监听 Binlog 实现题目变更时的实时预渲染。为预防热点数据击穿，实施全量题目及新增热点题目的预渲染策略。当渲染服务异常时自动降级为客户端渲染模式。</li><li><strong>设计实现设备维修系统</strong>。主导设计了硬件设备故障寄修的全流程维修系统，构建基于状态机的维修工单流转机制，通过标准化状态同步接口（如维修单同步、检测结果同步、支付状态同步等）实现与多家第三方维修工厂的高效对接，实现新增工厂接入开发成本在 1 周内。系统对接了支付中台、物流、短信等系统，并采用 OAuth2 的 client_credentials 模式保障第三方工厂系统的授权与安全调用。采用 RocketMQ 延迟消息取消用户未支付的维修单。用户成功支付维修费用后，通过消息重试+补偿日志表+补偿 JOB 的方式实现本系统与第三方系统的维修订单状态的一致性同步，并通过每周对账机制确保多系统间维修数据一致，系统间状态一致率超 99.9%。</li><li><strong>实现本地缓存监控组件</strong>。开发本地缓存监控组件，实现对 Guava Cache 和 Caffeine 本地缓存的统一监控与指标采集。组件采用线程安全设计，通过定时自动采集包括缓存命中率、QPS、加载耗时、驱逐数量等多项核心指标，并异步上报至 Prometheus，同时结合 Grafana 实现监控可视化与异常告警。同时利用该组件进行本地缓存治理，发现并解决了 10+ 服务本地缓存的命中率低以及缓存加载时间长的问题。</li></ul><h4 id="小猿口算项目-核心研发-多项目主-r-2021-07-2023-04" tabindex="-1">小猿口算项目(核心研发/多项目主 R) 2021.07-2023.04 <a class="header-anchor" href="#小猿口算项目-核心研发-多项目主-r-2021-07-2023-04" aria-label="Permalink to &quot;小猿口算项目(核心研发/多项目主 R) 2021.07-2023.04&quot;">​</a></h4><p><strong>项目描述</strong>：小猿口算是一个学习辅导相关的 APP，基于拍照作业批改、在线练习等核心功能辅助学生学习，APP 日活用户近千万。</p><p><strong>工作内容</strong>：</p><ul><li><strong>核心拍照检查接口压测与优化</strong>。对拍照检查接口进行全链路压测，通过压测结果进行分析性能瓶颈并进行接口优化。针对压测发现的 CPU 使用率高、GC 频繁、依赖的上游服务响应超时（存在性能瓶颈）等问题，使用快慢接口分服务隔离部署并调整慢批改接口的 Tomcat 线程池参数，并采用预先上传图片的方案代替原有的接口直传 MultipartFile 文件方案，降低请求链路对于图片处理的负载。引入基于 Apache Common Pool 的内存池（64K 对齐），实现对服务内图片内存分配的池化，降低 GC 频率。为应对上游服务超时问题，对接口新增单机限流以应对突发流量，同时引入模型批改超时熔断、视觉识别超时自动切换模型（自研 OCR 降级为 Google OCR）等降级机制，以防止上游服务超时引发雪崩。优化后服务 P95 响应时间从 2.15s 优化至 1.50s，减少了 80% 长尾请求；GC 时长稳定，Full GC 频率降低。</li><li><strong>负责冬奥集福卡运营活动(近千万用户参与)</strong>。活动包含用户做任务收集冬奥卡碎片、抢万能卡、合成金卡等玩法，成功集齐碎片并合成金卡后可获得实物奖品。抢万能卡活动实现了基于 Redis + Lua 脚本的万能卡库存防超卖方案，通过原子操作确保并发抢卡（峰值 QPS 过万）下库存的准确性，同时使用本地缓存记录库存清空状态，拦截后续的无效请求。用户合成金卡成功后，采用本地消息表 + 消息队列 + 补偿任务等机制实现合卡与创建实物奖品订单的最终一致性。同时建立了相关的业务监控指标，提升活动期间系统的可用性和数据一致性。</li><li><strong>实现亿级图片转换与 CDN 缓存</strong>。通过搭建图片 CDN 源站服务统一管理图片处理逻辑和缓存策略，解决原始图片直接暴露的安全风险和处理逻辑分散问题。系统根据不同业务场景使用不同策略对资源图片进行实时处理，包括压缩、格式转换、倾斜矫正和水印添加等流程，转换后图片通过多级缓存（CDN 边缘节点 + Redis）以加速访问。通过图片处理过程降级机制与双 CDN 灾备方案（阿里云+腾讯云）保障服务高可用。通过夜间全球 CDN 预热策略，使海外用户图片 P95 加载时长降低 60ms。</li></ul><h3 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h3><p><strong>所获奖项</strong>：国家奖学金(2016)、重庆大学优秀学生(2016)、国家励志奖学金(2017)、重庆大学优秀毕业生(2018)</p><p><strong>个人评价</strong>：做事负责有耐心，乐于沟通。热爱技术，有持续学习新技术的欲望。</p>',19)])])}const _=t(i,[["render",e]]);export{c as __pageData,_ as default};
